import React from 'react';
import { Routes, Route } from "react-router-dom";
import Navbar from "./components/Navbar/Navbar";
import Dealers from "./components/Dealers/Dealers";
import Login from "./components/Login/Login";
import Register from "./components/Register/Register";

// Add these placeholders so the app stops crashing
const AdminDashboard = () => <div className="glass-card"><h1>Admin Dashboard</h1></div>;
const ReviewsDashboard = () => <div className="glass-card"><h1>Reviews Dashboard</h1></div>;

function App() {
  return (
    <div>
      <Navbar />
      <Routes>
        <Route path="/" element={<Dealers />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/admin" element={<AdminDashboard />} />
        <Route path="/reviews" element={<ReviewsDashboard />} />
      </Routes>
    </div>
  );
}
export default App;
